using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Logging;
using OpenAI;

// --- Configuration ---
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

const string modelId = "gpt-4o-mini-2024-07-18";

// --- DI container ---
var services = new ServiceCollection();
services.AddLogging(b => b.AddConsole().SetMinimumLevel(LogLevel.Warning));
services.AddHttpClient();
services.AddSingleton(new OpenAIClient(apiKey));
services.AddChatClient(b => b.UseOpenAIChatClient(modelId));
services.AddSingleton<NoteService>();

var sp = services.BuildServiceProvider();

// --- Tools ---
var noteService = sp.GetRequiredService<NoteService>();
var httpFactory = sp.GetRequiredService<IHttpClientFactory>();

var tools = new AITool[]
{
    AIFunctionFactory.Create(
        ([Description("The search query")] string query) =>
        {
            return WebSearchAsync(httpFactory, query);
        },
        "web_search",
        "Searches the web for the given query and returns a list of results with titles, URLs, and snippets."),

    AIFunctionFactory.Create(
        ([Description("Title or key phrase for the note")] string title,
         [Description("Content to save")] string content) =>
        {
            noteService.Add(title, content);
            return $"Note saved: \"{title}\"";
        },
        "save_note",
        "Saves a research note for later reference. Use this to record important findings."),

    AIFunctionFactory.Create(
        () => noteService.GetAll(),
        "get_notes",
        "Retrieves all saved research notes so far."),
};

// --- Agent ---
var chatClient = sp.GetRequiredService<IChatClient>();
var agent = new ChatClientAgent(
    chatClient,
    instructions: """
        You are a research agent. Your workflow:
        1. Use web_search to find information about the user's topic.
        2. Use save_note to record each key finding.
        3. After gathering enough information (at least 3 searches), use get_notes
           to review your notes, then produce a clear, well-structured summary
           with references.
        Always cite sources with URLs. Be thorough but concise.
        """,
    name: "ResearchAgent",
    description: "An agent that researches topics using web search and note-taking.",
    tools: tools);

// --- Run ---
Console.WriteLine("╔══════════════════════════════════════╗");
Console.WriteLine("║      AI Research Agent (.NET 10)      ║");
Console.WriteLine("╚══════════════════════════════════════╝");
Console.WriteLine();

string topic = args.Length > 0
    ? string.Join(' ', args)
    : PromptUser();

Console.WriteLine($"\n🔍 Researching: {topic}\n");

var runOptions = new ChatClientAgentRunOptions
{
    ChatOptions = new ChatOptions
    {
        Temperature = 0f,
        MaxOutputTokens = 2048,
    },
};

var response = await agent.RunAsync(
    $"Research the following topic and provide a comprehensive summary: {topic}",
    options: runOptions);

Console.WriteLine("═══════════════ Results ═══════════════");
Console.WriteLine(response.Text);
Console.WriteLine("═══════════════════════════════════════");

var notes = noteService.GetAll();
if (notes.Count > 0)
{
    Console.WriteLine($"\n📝 {notes.Count} note(s) saved during research.");
}

return;

// --- Helpers ---

static string PromptUser()
{
    Console.Write("Enter a research topic: ");
    var input = Console.ReadLine()?.Trim();
    if (string.IsNullOrWhiteSpace(input))
    {
        Console.Error.WriteLine("No topic provided.");
        Environment.Exit(1);
    }

    return input;
}

static async Task<string> WebSearchAsync(IHttpClientFactory factory, string query)
{
    // Uses the DuckDuckGo Instant Answer API (no key required)
    using var http = factory.CreateClient();
    var encoded = Uri.EscapeDataString(query);
    var url = $"https://api.duckduckgo.com/?q={encoded}&format=json&no_html=1&skip_disambig=1";

    try
    {
        var doc = await http.GetFromJsonAsync<JsonElement>(url);

        var results = new List<string>();

        // Abstract (main topic summary)
        var abs = doc.GetProperty("Abstract").GetString();
        var absUrl = doc.GetProperty("AbstractURL").GetString();
        if (!string.IsNullOrWhiteSpace(abs))
        {
            results.Add($"Summary: {abs}\nSource: {absUrl}");
        }

        // Related topics
        if (doc.TryGetProperty("RelatedTopics", out var topics))
        {
            foreach (var topic in topics.EnumerateArray().Take(5))
            {
                var text = topic.TryGetProperty("Text", out var t) ? t.GetString() : null;
                var link = topic.TryGetProperty("FirstURL", out var u) ? u.GetString() : null;
                if (!string.IsNullOrWhiteSpace(text))
                {
                    results.Add($"- {text}\n  URL: {link}");
                }
            }
        }

        return results.Count > 0
            ? string.Join("\n\n", results)
            : $"No detailed results found for \"{query}\". Try a more specific query.";
    }
    catch (Exception ex)
    {
        return $"Search failed for \"{query}\": {ex.Message}";
    }
}

// --- Services ---

sealed class NoteService
{
    private readonly List<(string Title, string Content, DateTime Timestamp)> _notes = [];

    public void Add(string title, string content)
    {
        _notes.Add((title, content, DateTime.UtcNow));
    }

    public IReadOnlyList<string> GetAll()
    {
        return _notes
            .Select((n, i) => $"[{i + 1}] {n.Title} ({n.Timestamp:HH:mm:ss})\n{n.Content}")
            .ToList();
    }
}

